+        async_req.response = allocator.dupe(u8, resp.body) catch null;
+        async_req.status = @intCast(resp.status);
+        async_req.state.store(.complete, .release);
+        resp.deinit();
+    } else |_| {
+        async_req.status = -1;
+        async_req.state.store(.failed, .release);
